const tables = {
  mechanic: "Battle Puzzle Mechanic",
  descriptor: "Puzzle Descriptors",
  object: "Fantasy Objects"
};

async function drawFromTable(tableName) {
  const table = game.tables.getName(tableName);

  if (!table) {
    ui.notifications.error(`RollTable "${tableName}" not found.`);
    return null;
  }

  const roll = await table.roll();
  const result = roll.results[0];

  return {
    roll: result.range[0],
    text: result.text
  };
}

// Roll number of mechanics
const mechanicCountRoll = await new Roll("1d3").evaluate();
const mechanicCount = mechanicCountRoll.total;

let content = `
<h2>🧩 Battlefield Mechanics</h2>

<p>
<strong>Mechanics Generated:</strong> ${mechanicCount}
</p>
`;

for (let i = 1; i <= mechanicCount; i++) {

  const mechanic = await drawFromTable(tables.mechanic);
  const descriptor = await drawFromTable(tables.descriptor);
  const object = await drawFromTable(tables.object);

  content += `
    <hr>

    <h3>Mechanic ${i}</h3>

    <ul>
      <li><strong>Mechanic:</strong> [${mechanic.roll}] ${mechanic.text}</li>
      <li><strong>Descriptor:</strong> [${descriptor.roll}] ${descriptor.text}</li>
      <li><strong>Object:</strong> [${object.roll}] ${object.text}</li>
    </ul>
  `;
}

ChatMessage.create({
  user: game.user.id,
  speaker: ChatMessage.getSpeaker(),
  content
});
